{
  "model": "claude-sonnet-4-20250514",
  "max_tokens": 1500,
  "system": "Eres un consultor SEO experto. Responde siempre en español. El usuario te proporciona datos de análisis PSI de un sitio web. Debes generar: 1 párrafo diagnóstico (máx 100 palabras), lista de Top 3 problemas, lista de Top 3 oportunidades, y 5 recomendaciones priorizadas. Responde en JSON con keys: diagnostico, problemas, oportunidades, recomendaciones",
  "messages": [
    {
      "role": "user",
      "content": "Sitio: {{$node[\"webhook\"].json.url}}\nSector: {{$node[\"webhook\"].json.sector}}\nPerf Móvil: {{$node[\"psi_mobile\"].json.lighthouseResult.categories.performance.score}}\nSEO Score: {{$node[\"psi_mobile\"].json.lighthouseResult.categories.seo.score}}\nLCP: {{$node[\"psi_mobile\"].json.lighthouseResult.audits['largest-contentful-paint'].numericValue}}ms"
    }
  ]
}

parameters.functionCode:
const psiMobile = $input.all()[0].json['psi_mobile']?.json || {};
const psiDesktop = $input.all()[1].json['psi_desktop']?.json || {};
const claudeResponse = $input.all()[2].json['claude_analysis']?.json?.content?.[0]?.text || '{}';

let claudeData = {};
try {
  claudeData = JSON.parse(claudeResponse);
} catch (e) {
  claudeData = { diagnostico: 'Análisis completado', problemas: [], oportunidades: [], recomendaciones: [] };
}

const perfMobile = psiMobile.lighthouseResult?.categories?.performance?.score ?? 0;
const perfDesktop = psiDesktop.lighthouseResult?.categories?.performance?.score ?? 0;
const seoScore = psiMobile.lighthouseResult?.categories?.seo?.score ?? 0;
const lcp = psiMobile.lighthouseResult?.audits?.['largest-contentful-paint']?.numericValue ?? 0;
const inp = psiMobile.lighthouseResult?.audits?.['interaction-to-next-paint']?.numericValue ?? 0;
const cls = psiMobile.lighthouseResult?.audits?.['cumulative-layout-shift']?.numericValue ?? 0;

let score = 0;
if (perfMobile > 0.75) score += 2; else if (perfMobile > 0.5) score += 1;
if (seoScore > 0.8) score += 2; else if (seoScore > 0.6) score += 1;
if (lcp <= 2500) score += 2; else if (lcp <= 4000) score += 1;
if (perfDesktop > 0.9) score += 2; else if (perfDesktop > 0.7) score += 1;
if (cls <= 0.1) score += 2; else if (cls <= 0.25) score += 1;
score = Math.min(Math.max(score, 0), 20);

const semaphore = score >= 15 ? 'green' : score >= 10 ? 'orange' : 'red';

return {
  score,
  semaphore,
  perfMobile: Math.round(perfMobile * 100),
  perfDesktop: Math.round(perfDesktop * 100),
  seoScore: Math.round(seoScore * 100),
  lcp,
  inp,
  cls,
  diagnostico: claudeData.diagnostico || 'Análisis completado',
  problemas: claudeData.problemas || [],
  oportunidades: claudeData.oportunidades || [],
  recomendaciones: claudeData.recomendaciones || []
};
